109→function seedStore(points: number) {
110→  const state = useRootStore.getState() as any;
111→  if (state.pointsExtractActions) {
112→    state.pointsExtractActions.setBalance(points);
113→  }
114→}
115→
116→function LearnMoreSection({ isLoading }: { isLoading: boolean }) {
117→  if (isLoading) {
118→    return (
119→      <Box>
120→        <Text type="paragraphXXXL" mb="xxxs">
121→          Saiba mais
122→        </Text>
123→        {[1, 2, 3].map(i => (
124→          <Skeleton key={i} width={350} height={72} mb="xxs" />
125→        ))}
126→      </Box>
127→    );
128→  }
129→
130→  return (
131→    <Box>
132→      <Text type="paragraphXXXL" mb="xxxs">
133→        Saiba mais
134→      </Text>
135→      {MOCK_LEARN_MORE_DATA.map(item => (
136→        <CardActivity
137→          key={item.category}
138→          title={item.category}
139→          titleTextType={'paragraphMD' as any}
140→          mt="nano"
141→          icon={item.icon}
142→          onPress={() => {}}
143→          showIcon
144→          showIconRight
145→          descriptionColor="INTENSE_COLOR_05"
146→          iconRight="icon-next"
147→          showButton={false}
148→          showTagLabel={false}
149→        />
150→      ))}
151→    </Box>
152→  );
153→}
154→
155→function PointsStoryWrapper({
156→  points = 15320,
157→  isLoading = false,
158→}: {
159→  points?: number;
160→  isLoading?: boolean;
161→}) {
162→  const [isMyOrders, setIsMyOrders] = useState(false);
163→
164→  useEffect(() => {
165→    seedStore(points);
166→  }, [points]);
167→
168→  return (
169→    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
170→      <Header
171→        title={isMyOrders ? 'Meu espaço' : 'Programa de Pontos'}
172→        iconLeft="icon-back"
173→        hideLeftIcon={false}
174→        onBack={() => {
175→          if (isMyOrders) {
176→            setIsMyOrders(false);
177→          }
178→        }}
179→        isOption={!isMyOrders}
180→        iconRight="icon-menu"
181→        onPressIconRight={() => setIsMyOrders(true)}
182→      />
183→      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
184→        {isMyOrders ? (
185→          <CardActivity
186→            isLoading={isLoading}
187→            icon="icon-shopping-bag"
188→            showIcon
189→            showIconRight={false}
190→            hideBackground
191→            hideBorder
192→            title="Meus pedidos"
193→            titleTextType="paragraphXL"
194→            onPress={() => {}}
195→          />
196→        ) : (
197→          <Box ml="smaller" mr="smaller">
198→            <CardPoints
199→              icon="icon-benefits"
200→              iconInfo="icon-help"
201→              iconAction="icon-next"
202→              isLoading={isLoading}
203→              mt="smaller"
204→              mb="xs"
205→              onPressIconInfo={() => {}}
206→              onPressExtract={() => {}}
207→              textExtract="Extrato completo"
208→              title="Pontos disponíveis"
209→              valuePoints={formatPoints(points ?? 0)}
210→            />
211→
212→            <Text type="paragraphXXXL" mb="xxxs">
213→              Onde usar meus pontos
214→            </Text>
215→
216→            <CardMiddle
217→              items={MOCK_ITEMS as any}
218→              renderType="grid"
219→              isLoading={isLoading}
220→              mb="xs"
221→            />
222→
223→            <LearnMoreSection isLoading={isLoading} />
224→          </Box>
225→        )}
226→      </ScrollView>
227→    </Box>
228→  );
229→}
230→
231→const meta: Meta<typeof PointsStoryWrapper> = {
232→  title: 'Screens/Points',
233→  component: PointsStoryWrapper,
234→  decorators: [NavigationDecorator],
235→};
236→
237→export default meta;
238→type Story = StoryObj<typeof PointsStoryWrapper>;
239→
