  1→import { useFocusEffect } from '@react-navigation/native';
  2→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
  3→import React, {
  4→  FC,
  5→  useCallback,
  6→  useEffect,
  7→  useMemo,
  8→  useRef,
  9→  useState,
 10→} from 'react';
 11→import {
 12→  eventModalView,
 13→  eventScreenViewV3,
 14→  eventSelectContent,
 15→} from '~/constants/functions';
 16→import ApiError from '../../atomic/organisms/ApiError';
 17→import BasicScreen from '../../atomic/templates/BasicScreen';
 18→import { useCardBuilderWhereUseMyPoints } from '../../hooks/custom/useCardBuilderWhereUseMyPoints';
 19→import { getParameterPointsProgram, usePoints } from '../../services';
 20→import { PointsProps } from './Models';
 21→import PointsView from './view';
 22→
 23→const Points: FC<PointsProps> = ({ navigation }) => {
 24→  const {
 25→    points,
 26→    products,
 27→    isLoadingBalance,
 28→    isErrorBalance,
 29→    isErrorProducts,
 30→    requestInitialData,
 31→    requestPointsBalance,
 32→    requestPointsProducts,
 33→    clear,
 34→    clearBalance,
 35→  } = usePoints();
 36→  const hasFocused = useRef(false);
 37→  const modalizeRef = useRef<PropsModalizeRef>(
 38→    null as unknown as PropsModalizeRef,
 39→  );
 40→  const [isMyOrders, setIsMyOrders] = useState(false);
 41→
 42→  const handleMyOrders = useCallback(() => {
 43→    navigation.navigate('MyOrdersRewardProgram');
 44→  }, [navigation]);
 45→
 46→  const handleGoBack = useCallback(() => {
 47→    navigation.goBack();
 48→  }, [navigation]);
 49→
 50→  const handlerGoHome = useCallback(() => {
 51→    navigation.navigate('Home' as never);
 52→  }, [navigation]);
 53→
 54→  const handleOpenDefault = () => {
 55→    eventSelectContent({
 56→      content_type: 'cta',
 57→      content_id: 'informacao_pontos',
 58→      location_1: 'monetizacao',
 59→      location_2: 'hub_recompensas_spmais',
 60→      location_3: 'home_hub_recompensas',
 61→    });
 62→
 63→    modalizeRef.current?.open?.();
 64→  };
 65→
 66→  const handleOpenMyOrders = () => {
 67→    setIsMyOrders(true);
 68→
 69→    eventModalView({
 70→      content_id: 'menu_header',
 71→      location_1: 'monetizacao',
 72→      location_2: 'hub_recompensas_spmais',
 73→      location_3: 'home_hub_recompensas',
 74→    });
 75→  };
 76→
 77→  const buildPointsCardItems = useCardBuilderWhereUseMyPoints();
 78→
 79→  const requestPointsCallback = useCallback(() => {
 80→    requestPointsBalance();
 81→    requestPointsProducts();
 82→    getParameterPointsProgram();
 83→  }, [
 84→    requestPointsBalance,
 85→    requestPointsProducts,
 86→  ]);
 87→
 88→  const handleApiErrorPress = useCallback(() => {
 89→    if (isErrorBalance || isErrorProducts) {
 90→      requestPointsCallback();
 91→    }
 92→  }, [
 93→    isErrorBalance,
 94→    isErrorProducts,
 95→    requestPointsCallback,
 96→  ]);
 97→
 98→  useFocusEffect(
 99→    useCallback(() => {
100→      if (!hasFocused.current) {
101→        eventScreenViewV3(
102→          'home_hub_recompensas',
103→          'hub_recompensas_spmais',
104→          'monetizacao',
105→          {
106→            location_1: 'monetizacao',
107→            location_2: 'hub_recompensas_spmais',
108→            location_3: 'home_hub_recompensas',
109→          },
110→        );
111→        hasFocused.current = true;
112→        clearBalance();
113→      }
114→      return () => {
115→        hasFocused.current = false;
116→      };
117→    }, [clearBalance]),
118→  );
119→
120→  useEffect(() => {
121→    requestInitialData();
122→
123→    return () => {
124→      clear();
125→    };
126→  }, [
127→    requestInitialData,
128→    clear,
129→  ]);
130→
131→  useFocusEffect(
132→    useCallback(() => {
133→      requestPointsCallback();
134→      return undefined;
135→    }, [requestPointsCallback]),
136→  );
137→
138→  const view = useMemo(() => {
139→    if (isErrorProducts || isErrorBalance) {
140→      return (
141→        <BasicScreen
142→          leftIconOnPress={handleGoBack}
143→          title="Programa de Pontos"
144→          errorButtonOnPress={handleApiErrorPress}
145→        >
146→          <ApiError onPress={handleApiErrorPress} />
147→        </BasicScreen>
148→      );
149→    }
150→
151→    const normalizedItems = buildPointsCardItems(products);
152→
153→    const onOpenExtract = () => {
154→      eventSelectContent({
155→        content_type: 'cta',
156→        content_id: 'exibir_extrato',
157→        location_1: 'monetizacao',
158→        location_2: 'hub_recompensas_spmais',
159→        location_3: 'home_hub_recompensas',
160→      });
161→      navigation.navigate('ExtractRewardProgram', {
162→        analytics: {
163→          screen_name: 'extrato_hub_recompensas',
164→          screen_class: 'hub_recompensas_spmais',
165→          screen_bussines: 'monetizacao',
166→          screen_info: {
167→            location_1: 'monetizacao',
168→            location_2: 'hub_recompensas_spmais',
169→            location_3: 'extrato_hub_recompensas',
170→          },
171→        },
172→      });
173→    };
174→
175→    return (
176→      <PointsView
177→        items={normalizedItems}
178→        isLoadingBalance={isLoadingBalance}
179→        handleGoBack={handleGoBack}
180→        pointsAvailable={points}
181→        pointsOptions={products}
182→        onOpenExtract={onOpenExtract}
183→        onOpenDefault={handleOpenDefault}
184→        modalizeRef={modalizeRef}
185→        isMyOrders={isMyOrders}
186→        setIsMyOrders={setIsMyOrders}
187→        handlerGoHome={handlerGoHome}
188→        onMenuPress={handleOpenMyOrders}
189→        handleMyOrders={handleMyOrders}
190→      />
191→    );
192→  }, [
193→    points,
194→    products,
195→    isLoadingBalance,
196→    isErrorBalance,
197→    isErrorProducts,
198→    navigation,
199→    buildPointsCardItems,
200→    isMyOrders,
201→    handleApiErrorPress,
202→    handleGoBack,
203→    handleMyOrders,
204→    handlerGoHome,
205→  ]);
206→
207→  return view;
208→};
209→
210→export default Points;
211→

 1→import {
 2→  Box,
 3→  CardActivity,
