 5→  CardPoints,
 6→  Text,
 7→} from '@semparar/design-system-app';
 8→import React, { FC } from 'react';
 9→
10→import { PropsCardMiddle } from '@semparar/design-system-app/src/atomic/molecules/Cards/CardMiddle/Models';
11→import LearnMorePointsSection from '../../atomic/organisms/LearnMorePointsSection';
12→import PointsInfoBottomSheet from '../../atomic/organisms/PointsInfoBottomSheet';
13→import BasicScreen from '../../atomic/templates/BasicScreen';
14→import { formatPoints } from '../../utils/formatPoints';
15→import { PointsViewProps } from './Models';
16→
17→const PointsView: FC<PointsViewProps> = ({
18→  isLoadingBalance,
19→  handleGoBack,
20→  pointsAvailable,
21→  items,
22→  onOpenExtract,
23→  onOpenDefault,
24→  modalizeRef,
25→  isMyOrders,
26→  setIsMyOrders,
27→  onMenuPress,
28→  handleMyOrders,
29→}) => {
30→  return (
31→    <>
32→      <BasicScreen
33→        errorButtonOnPress={() => {}}
34→        hasScroll
35→        leftIconOnPress={() => {
36→          isMyOrders ? setIsMyOrders(false) : handleGoBack();
37→        }}
38→        rightIcon="icon-menu"
39→        rightIconOnPress={onMenuPress}
40→        hasRightIcon={!isMyOrders}
41→        title={isMyOrders ? 'Meu espaço' : 'Programa de Pontos'}
42→      >
43→        {isMyOrders ? (
44→          <CardActivity
45→            isLoading={isLoadingBalance}
46→            icon="icon-shopping-bag"
47→            showIcon
48→            showIconRight={false}
49→            hideBackground
50→            hideBorder
51→            title="Meus pedidos"
52→            titleTextType="paragraphXL"
53→            onPress={handleMyOrders}
54→          />
55→        ) : (
56→          <Box ml="smaller" mr="smaller">
57→            <CardPoints
58→              icon="icon-benefits"
59→              iconInfo="icon-help"
60→              iconAction="icon-next"
61→              isLoading={isLoadingBalance}
62→              mt="smaller"
63→              mb="xs"
64→              onPressIconInfo={onOpenDefault}
65→              onPressExtract={() => onOpenExtract()}
66→              textExtract="Extrato completo"
67→              title="Pontos disponíveis"
68→              valuePoints={formatPoints(pointsAvailable ?? 0)}
69→            />
70→
71→            <Text type="paragraphXXXL" mb="xxxs">
72→              Onde usar meus pontos
73→            </Text>
74→
75→            <CardMiddle
76→              items={items as PropsCardMiddle['items']}
77→              renderType="grid"
78→              isLoading={isLoadingBalance}
79→              mb="xs"
80→            />
81→
82→            <LearnMorePointsSection />
83→          </Box>
84→        )}
85→      </BasicScreen>
86→      <PointsInfoBottomSheet modalizeRef={modalizeRef} />
87→    </>
88→  );
89→};
90→
91→export default PointsView;
