17→    useShallow(state => state.pointsProducts),
18→  );
19→  const pointsBalance = useRootStore(useShallow(state => state.pointsBalance));
20→  const parameterPointsProgram = useRootStore(
21→    useShallow(state => state.parameterPointsProgram),
22→  );
23→
24→  const requestInitialData = useCallback(async () => {
25→    await Promise.all([
26→      getPointsBalance(),
27→      getPointsProducts(),
28→      getParameterPointsProgram(),
29→    ]);
30→  }, []);
31→
32→  const requestPointsBalance = useCallback(async () => {
33→    await getPointsBalance();
34→  }, []);
35→
36→  const requestPointsProducts = useCallback(async () => {
37→    await getPointsProducts();
38→  }, []);
39→
40→  const requestParameterization = useCallback(async () => {
41→    await getParameterPointsProgram();
42→  }, []);
43→
44→  const clear = useCallback(() => {
45→    const { pointsProductsActions } = useRootStore.getState();
46→    pointsProductsActions.reset();
47→  }, []);
48→
49→  const clearBalance = useCallback(() => {
50→    const { pointsExtractActions } = useRootStore.getState();
