 40→}
 41→
 42→const INITIAL_POINTS_EXTRACT_STATE: PointsExtractState = {
 43→  extractData: undefined,
 44→  processedExtractData: undefined,
 45→  status: PointsExtractStatus.IDLE,
 46→  isLoadingMore: false,
 47→  error: undefined,
 48→};
 49→
 50→const INITIAL_POINTS_BALANCE_STATE: PointsBalanceState = {
 51→  points: undefined,
 52→  status: PointsBalanceStatus.IDLE,
 53→  error: undefined,
 54→};
 55→
 56→const INITIAL_POINTS_EXTRACT_FILTERS_STATE: PointsExtractFiltersState = {
 57→  appliedTransactionsFilters: undefined,
 58→  appliedExpiringFilters: undefined,
 59→};
 60→
 61→export const createPointsExtractSlice: StateCreator<
 62→  PointsExtractSlice,
 63→  [],
 64→  [],
 65→  PointsExtractSlice
 66→> = set => ({
 67→  pointsExtract: INITIAL_POINTS_EXTRACT_STATE,
 68→  pointsBalance: INITIAL_POINTS_BALANCE_STATE,
 69→  pointsExtractFilters: INITIAL_POINTS_EXTRACT_FILTERS_STATE,
 70→  pointsExtractActions: {
 71→    setExtractStatus: status =>
 72→      set(state => ({
 73→        pointsExtract: {
 74→          ...state.pointsExtract,
 75→          status,
 76→          ...(status === PointsExtractStatus.IDLE ||
 77→          status === PointsExtractStatus.LOADING
 78→            ? { error: undefined }
 79→            : {}),
 80→        },
 81→      })),
 82→    setExtractData: (extractData, processedExtractData) =>
 83→      set(state => ({
 84→        pointsExtract: {
 85→          ...state.pointsExtract,
 86→          extractData,
 87→          processedExtractData,
 88→          status: PointsExtractStatus.SUCCESS,
 89→          isLoadingMore: false,
 90→          error: undefined,
 91→        },
 92→      })),
 93→    appendExtractData: (extractData, processedExtractData) =>
 94→      set(state => {
 95→        const existingTransactions =
 96→          state.pointsExtract.extractData?.transactions ?? [];
 97→        const newTransactions = extractData.transactions;
 98→        const mergedTransactions = [
 99→          ...existingTransactions,
100→          ...newTransactions,
101→        ];
102→
103→        const existingProcessed = state.pointsExtract.processedExtractData;
104→        const newProcessed = processedExtractData;
105→
106→        let mergedProcessed: ProcessedExtractData | undefined;
107→        if (existingProcessed && newProcessed) {
108→          const existingMapped = existingProcessed.mappedTransactions ?? [];
109→          const newMapped = newProcessed.mappedTransactions ?? [];
110→          mergedProcessed = {
111→            groupedTransactions: newProcessed.groupedTransactions,
112→            mappedTransactions: [
113→              ...existingMapped,
114→              ...newMapped,
115→            ],
116→          };
117→        } else {
118→          mergedProcessed = newProcessed ?? existingProcessed;
119→        }
120→
121→        return {
122→          pointsExtract: {
123→            ...state.pointsExtract,
124→            extractData: {
125→              transactions: mergedTransactions,
126→              pagination: extractData.pagination,
127→            },
128→            processedExtractData: mergedProcessed,
129→            isLoadingMore: false,
130→          },
131→        };
132→      }),
133→    setLoadingMore: isLoading =>
134→      set(state => ({
135→        pointsExtract: {
136→          ...state.pointsExtract,
137→          isLoadingMore: isLoading,
138→        },
139→      })),
140→    setBalanceStatus: status =>
141→      set(state => ({
142→        pointsBalance: {
143→          ...state.pointsBalance,
144→          status,
145→        },
146→      })),
147→    setBalance: points =>
148→      set(state => ({
149→        pointsBalance: {
150→          ...state.pointsBalance,
151→          points,
152→          status: PointsBalanceStatus.SUCCESS,
153→          error: undefined,
154→        },
155→      })),
156→    setTransactionsFilters: filters =>
157→      set(state => ({
158→        pointsExtractFilters: {
159→          ...state.pointsExtractFilters,
160→          appliedTransactionsFilters: filters,
161→        },
162→      })),
163→    clearTransactionsFilters: () =>
164→      set(state => ({
165→        pointsExtractFilters: {
166→          ...state.pointsExtractFilters,
167→          appliedTransactionsFilters: undefined,
168→        },
169→      })),
170→    setExpiringFilters: filters =>
171→      set(state => ({
172→        pointsExtractFilters: {
173→          ...state.pointsExtractFilters,
174→          appliedExpiringFilters: filters,
175→        },
176→      })),
177→    clearExpiringFilters: () =>
178→      set(state => ({
179→        pointsExtractFilters: {
180→          ...state.pointsExtractFilters,
181→          appliedExpiringFilters: undefined,
182→        },
183→      })),
184→    reset: () =>
185→      set({
186→        pointsExtract: INITIAL_POINTS_EXTRACT_STATE,
187→        pointsBalance: INITIAL_POINTS_BALANCE_STATE,
188→        pointsExtractFilters: INITIAL_POINTS_EXTRACT_FILTERS_STATE,
189→      }),
190→    clearBalance: () =>
191→      set({
