      <ThemeProvider>
        <Story />
      </ThemeProvider>
    ),
  ],
  globalTypes: {
    ...phoneFrameGlobalTypes,
  },
  initialGlobals: {
    ...phoneFrameInitialGlobals,
  },
  parameters: {
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i,
      },
    },
  },
};

export default preview;
```

